import{_ as i,c as t,o,a5 as n,ba as a,bb as r,bc as d,bd as l,be as s,bf as c,aZ as m}from"./chunks/framework.Dm71djiW.js";const y=JSON.parse('{"title":"Version Change Log v2025.1","description":"","frontmatter":{"title":"Version Change Log v2025.1"},"headers":[],"relativePath":"docs/changelog-v2025.1.x.md","filePath":"docs/changelog-v2025.1.x.md","lastUpdated":1772156779000}'),h={name:"docs/changelog-v2025.1.x.md"};function g(p,e,u,f,b,v){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="liii-stem-v2025-1-version-change-log" tabindex="-1">Liii STEM v2025.1 Version Change Log <a class="header-anchor" href="#liii-stem-v2025-1-version-change-log" aria-label="Permalink to тАЬLiii STEM v2025.1 Version Change LogтАЭ">тАЛ</a></h1><h2 id="тнРя╕П-new-features-and-highlights" tabindex="-1">тнРя╕П New Features and Highlights <a class="header-anchor" href="#тнРя╕П-new-features-and-highlights" aria-label="Permalink to тАЬтнРя╕П New Features and HighlightsтАЭ">тАЛ</a></h2><ol><li><strong>AI streaming output + toolbar entry</strong>: AI features now stream responses and are accessible from a dedicated toolbar entry for smoother interaction.</li><li><strong>LLM upgrade + new model support</strong>: Upgraded to <code>v20251024</code>, with new support for <strong>DeepSeek 3.2</strong> and <strong>Qwen 3</strong>. <img src="'+a+'" alt=""></li><li><strong>Handwriting / image OCR</strong>: Added an OCR model for handwritten formulas and image recognition. <img src="'+r+'" alt=""></li><li><strong>Comments</strong>: Insert comments and set comment authors (<code>Packages тЖТ Utilities тЖТ Comment</code>, <code>Ctrl+/</code> to insert), plus fold/unfold with <code>Alt+Shift+тЖС/тЖУ</code>. <img src="'+d+'" alt=""></li><li><strong>Emoji quick input</strong>: e.g. type <code>:anger:</code> to insert <code>ЁЯТв</code>. <img src="'+l+'" alt=""></li><li><strong>Custom start number for ordered lists</strong>: set the starting index via <code>item-nr</code>, and keep numbering independent across lists. <img src="'+s+'" alt=""></li><li><strong>Statistics window improvements</strong>: more complete info, with better layout and sizing. <img src="'+c+'" alt=""></li><li><strong>Themes &amp; UI</strong>: added <strong>Liii Dark</strong> theme, icon polish, and fixes for dark theme and <code>course</code> style buttons.</li><li><strong>Editing &amp; typesetting</strong>: smarter Tab completion, more shortcuts, richer alignment/list styles, and better math font/symbol support (incl. <code>\\mathscr</code>).</li><li><strong>Export &amp; stability</strong>: PDF export supports Emoji, better image embedding, and multiple key stability fixes.</li></ol><h2 id="ЁЯМЯ-summary" tabindex="-1">ЁЯМЯ Summary <a class="header-anchor" href="#ЁЯМЯ-summary" aria-label="Permalink to тАЬЁЯМЯ SummaryтАЭ">тАЛ</a></h2><p>Liii STEM v2025.1 focuses on productivity and polish: faster editing workflows, stronger math typesetting, a more complete comment system, expanded AI/OCR capabilities, improved PDF export, and many stability and cross-platform fixes.</p><h2 id="ЁЯФз-changelog" tabindex="-1">ЁЯФз Changelog <a class="header-anchor" href="#ЁЯФз-changelog" aria-label="Permalink to тАЬЁЯФз ChangelogтАЭ">тАЛ</a></h2><h3 id="liii-stem-v2025-1-6-2025-11-07" tabindex="-1">Liii STEM v2025.1.6 (2025.11.07) <a class="header-anchor" href="#liii-stem-v2025-1-6-2025-11-07" aria-label="Permalink to тАЬLiii STEM v2025.1.6 (2025.11.07)тАЭ">тАЛ</a></h3><ol><li>Ordered lists now support custom starting numbers (<code>item-nr</code>), and numbering stays independent across list environments.</li><li>Added comment insertion and author settings (<code>Packages тЖТ Utilities тЖТ Comment</code>), shortcut <code>Ctrl+/</code> to insert; comments can be folded/unfolded with <code>Alt+Shift+тЖС/тЖУ</code> (added in v2025.1.5 and highlighted again here).</li><li>Added the тАЬdoes not divideтАЭ symbol <code>тИд</code> to the Math Mode toolbar, with shortcut <code>|</code> then <code>/</code>.</li><li>In the environment toolbar, тАЬPreferences for tagтАЭ now supports switching chapter/section numbering formats.</li><li>Character counting now ignores line breaks.</li><li>In the <code>liii-night</code> theme, removed redundant indent/alignment buttons from the source-style toolbar.</li><li>Fixed button colors for <code>course</code> style in dark mode.</li><li>Fixed tooltip localization for тАЬInsert ellipseтАЭ.</li><li>Improved localization coverage for math superscript/subscript menu items and related task-document guidance.</li><li>Localized the dialog for <code>Edit тЖТ Search recent documents</code>.</li><li>Translation tweaks: тАЬalignment equationтАЭ тЖТ тАЬmulti-line equation (align)тАЭ, тАЬseveral equationтАЭ тЖТ тАЬmulti-line equation (eqnarray)тАЭ.</li><li>Prevented session menu items from being translated, keeping technical terms consistent.</li><li>Adjusted circled-number alignment: replaced <code>aligned-space-item</code> with <code>aligned-item</code> to avoid centering issues.</li><li>Fixed truncated text in the input box of тАЬSearch recent documentsтАЭ.</li><li>Fixed navigation commands (next/previous) unexpectedly changing the converter structure; now preserves the user-selected converter state.</li></ol><h3 id="liii-stem-v2025-1-5-2025-10-23" tabindex="-1">Liii STEM v2025.1.5 (2025.10.23) <a class="header-anchor" href="#liii-stem-v2025-1-5-2025-10-23" aria-label="Permalink to тАЬLiii STEM v2025.1.5 (2025.10.23)тАЭ">тАЛ</a></h3><ol><li>Improved the Statistics window (open via <code>Tools тЖТ Statistics</code>) with more complete information.</li><li>Optimized Statistics window styling: adjusted window width and data spacing.</li><li>Fixed a critical issue where Beamer mode couldnтАЩt switch pages (a regression from large-document optimizations).</li><li>Added macOS trackpad zoom support.</li><li>Fixed <code>\\mathcatalan</code> incorrectly rendering in italic; restored upright тАЬCтАЭ.</li><li>Added shortcut inputs for some Emoji.</li><li>Upgraded LLM to <code>v20251024</code>, removing some legacy models.</li><li>Added support for <strong>DeepSeek 3.2</strong> and <strong>Qwen 3</strong>.</li><li>Added an OCR model with built-in system prompts for handwritten formulas / image recognition.</li><li>Added comment insertion and author settings (<code>Packages тЖТ Utilities тЖТ Comment</code>), shortcut <code>Ctrl+/</code> to insert.</li><li>Comments can be folded/unfolded with <code>Alt+Shift+тЖС/тЖУ</code>.</li><li>Added a shortcut for the <code>align</code> environment: <code>Ctrl+$</code> (also added an option in the menu bar).</li><li>Emoji shortcut example: in Math Mode, type <code>:anger:</code> to insert <code>ЁЯТв</code>.</li><li>Fixed a plugin issue where continuous input kept stealing focus and the table of contents couldnтАЩt jump correctly.</li></ol><h3 id="liii-stem-v2025-1-4-2025-10-11" tabindex="-1">Liii STEM v2025.1.4 (2025.10.11) <a class="header-anchor" href="#liii-stem-v2025-1-4-2025-10-11" aria-label="Permalink to тАЬLiii STEM v2025.1.4 (2025.10.11)тАЭ">тАЛ</a></h3><ol><li>Fixed PDF export failing with Emoji; PDF export now supports Emoji.</li><li>Supports dragging images from the browser to embed (WebP not supported yet).</li><li>Added a тАЬ123тАЭ numbering button to the <code>align</code> toolbar, with shortcut <code>Ctrl+#</code>.</li><li>Presentation mode (<code>View</code>) now supports <code>Esc</code> to exit fullscreen.</li><li>Math Mode toolbar accent icons switched from PNG to SVG.</li><li>Read-only files now show a save prompt and a <code>[Read-only]</code> label; saving prompts тАЬSave asтАЭ.</li><li>Fixed comment feature enablement: the comment menu can be enabled via <code>Document тЖТ Style тЖТ Packages тЖТ Utilities тЖТ comment</code>.</li><li>Improved the dialog when closing buffered files to a тАЬSave / DonтАЩt saveтАЭ flow.</li><li>Known issue: when multiple temporary files exist, choosing тАЬSaveтАЭ only saves the current file; closing an existing file can still save modifications.</li><li>Fixed a ghosting issue where <code>&lt;</code>/<code>&gt;</code> + Tab showed <code>&lt;&gt;</code> in Math Mode.</li><li>Added MATLAB syntax highlighting: <code>Document тЖТ Style тЖТ Packages тЖТ Code тЖТ matlab</code>; create via <code>Insert тЖТ Macro тЖТ matlab</code>. Use <code>matlab</code> inline and <code>matlab-code</code> for code blocks.</li><li>Reduced view-zoom lag for large documents.</li><li>Preserves cursor position when switching between body and preamble.</li><li>Adjusted circled-number shortcuts to <code>@</code> + number + Tab (0-20) to avoid accidental triggers in email addresses.</li><li>Added parenthesized-number shortcut: <code>(</code> + number + Tab.</li><li>Added Roman numeral shortcuts: <code>I 5 Tab</code> тЖТ <code>тЕд</code>, <code>i 5 Tab</code> тЖТ <code>тЕ┤</code>.</li><li>Added ordered-list styles: Chinese numerals, circled numbers, and parenthesized numbers.</li><li>Adjusted ordered-list letter styles to <code>a. b. c.</code> and <code>A. B. C.</code>.</li><li>Added menu entries for ordered lists/arrangements: <code>Insert тЖТ Ordered list тАж</code> / <code>Insert тЖТ Ordered arrangement тАж</code>.</li><li>Optimized arrangement line spacing (smaller default).</li><li>Fixed gaps between table rows when tables break across pages.</li></ol><h3 id="liii-stem-v2025-1-3-2025-09-15" tabindex="-1">Liii STEM v2025.1.3 (2025.09.15) <a class="header-anchor" href="#liii-stem-v2025-1-3-2025-09-15" aria-label="Permalink to тАЬLiii STEM v2025.1.3 (2025.09.15)тАЭ">тАЛ</a></h3><ol><li>Fixed a freeze when inputting an ellipsis via Shift+6.</li><li>Fixed unresponsiveness caused by multiple copy operations after selecting all.</li><li>Fixed PDF export failure when image content and format didnтАЩt match.</li><li>Fixed the Gnuplot plugin not rendering correctly inside folded structures.</li><li>Windows installer now uses a code-signing certificate.</li><li>Added a dedicated installer for macOS 12.</li><li>Moved header/footer features into an auxiliary window.</li><li>Fixed duplicate submenu items for numbered single-line formulas.</li><li>Restored slide order adjustment buttons.</li><li>Supports embedding linked images, or dragging images directly into documents.</li><li>When selecting the dark theme, the app now prompts for restart and offers one-click restart.</li><li>Added friendlier dialogs when opening unreadable files and read-only files.</li><li>Added a success notification after PDF export completes.</li><li>Supports English hyphens in Chinese documents.</li><li>Updated table and matrix insertion shortcuts.</li><li>Added shortcuts for inserting additional math fonts.</li><li>Added quick input support for multiple integral symbol variants.</li><li>Added <code>\\mathscr</code> math font support.</li><li>Added an тАЬAppendixтАЭ insertion option in the mode toolbar.</li><li>Improved text highlight rendering.</li></ol><h3 id="liii-stem-v2025-1-2-2025-08-28" tabindex="-1">Liii STEM v2025.1.2 (2025.08.28) <a class="header-anchor" href="#liii-stem-v2025-1-2-2025-08-28" aria-label="Permalink to тАЬLiii STEM v2025.1.2 (2025.08.28)тАЭ">тАЛ</a></h3><ol><li>AI now supports streaming output, showing generation progress in real time.</li><li>AI features are integrated into a dedicated toolbar icon entry.</li><li>Theme updates: icon polish for the classic Liii theme, plus a new <strong>Liii Dark</strong> theme.</li><li>Search &amp; replace improvements: structured search/replace window embedded as an auxiliary window, supporting complex structures (e.g. formulas) via the Mode Toolbar.</li><li>Added Tab completion in the editing window, covering text, formulas, macro commands, and more.</li><li>macOS shortcuts: <code>Cmd+T</code> for new tabs, <code>Cmd+1-6</code> to switch tabs.</li><li>Multi-tab management improvements: added window attach/detach management and fixed many compatibility issues.</li><li>Improved file format option display in Save / Save As / Open dialogs.</li><li>Comprehensive performance optimizations: faster startup, more responsive editing, smoother rendering.</li><li>Math Mode multiplication symbol defaults to <code>├Ч</code>, and Tab can cycle through other multiplication symbols.</li><li>Added multi-integral macro support: <code>\\iint</code>, <code>\\oiint</code>, <code>\\iiint</code>, <code>\\oint</code>, <code>\\idotsint</code>, etc.</li><li>Magic Paste supports Emoji (beta) and smarter detection of more content types.</li><li>Enunciation environments now use European-style numbering (independent numbering per environment type).</li><li>Added the Assumption enunciation environment.</li><li>Fixed an issue on Windows where images on the D: drive couldnтАЩt be inserted.</li></ol><h2 id="ЁЯСП-join-us" tabindex="-1">ЁЯСП Join Us <a class="header-anchor" href="#ЁЯСП-join-us" aria-label="Permalink to тАЬЁЯСП Join UsтАЭ">тАЛ</a></h2><p>Join the Mogan community QQ group or our Discord community to connect with like-minded peers and get the latest Liii STEM news.</p><ul><li>Liii STEM Website: <a href="https://liiistem.com/" target="_blank" rel="noreferrer">https://liiistem.com/</a></li><li>Mogan community QQ group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt/hpydluCE/cF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ==&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="noreferrer">934456971</a></li><li>Discord: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="noreferrer">https://discord.gg/Q7xARnAf8t</a></li></ul><p align="center"><img src="'+m+'" width="55%"></p>',20)])])}const x=i(h,[["render",g]]);export{y as __pageData,x as default};
